import OpenAI from 'openai';
import { Verifier } from '@vex/sdk';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const verifier = new Verifier({ apiKey: process.env.VEX_API_KEY });

export async function POST(request: Request) {
  const event = await request.json();
  if (event.type === 'thread.run.completed') {
    const run = await openai.beta.threads.runs.retrieve(
      event.data.thread_id,
      event.data.id
    );
    const messages = await openai.beta.threads.messages.list(run.thread_id);
    const content = messages.data[0].content[0].text?.value || '';

    const result = await verifier.verify({
      prompt: content,
      domain: 'insurance',
      checks: ['naic_explainability', 'gdpr_pii', 'fcra_compliance']
    });

    if (!result.valid) {
      await openai.beta.threads.runs.cancel(run.thread_id, run.id);
      return Response.json({ blocked: true, violations: result.violations });
    }
  }
  return Response.json({ status: 'ok' });
}

from vex_sdk import Policy

insurance_policy = Policy(name='insurance-assistants', rules=[
    {
        'name': 'no_protected_classes',
        'type': 'regex_block',
        'pattern': r'\b(race|gender|ethnicity|religion|age>65)\b.*(premium|rate|deny)',
        'severity': 'critical'
    },
    {
        'name': 'explainable_denial',
        'type': 'structured_check',
        'schema': {
            'denial_reason': {'type': 'string', 'min_length': 50},
            'evidence': {'type': 'array', 'items': {'type': 'string'}}
        }
    },
    {
        'name': 'pii_masking',
        'type': 'pii_detection',
        'fields': ['ssn', 'policy_number'],
        'action': 'redact'
    }
])

# Apply to webhook
verifier.apply_policy(insurance_policy.id)
